SELECT rupture_mechanism, MAX(rupture_length) AS max_rupture_length
FROM earthquake_ruptures
GROUP BY rupture_mechanism;

SELECT rupture_id, rupture_length
FROM earthquake_ruptures
WHERE rupture_mechanism = 'normal' AND rupture_length > 5;

SELECT fault_type 
FROM faults 
WHERE fault_id = 1;

SELECT tool_name
FROM analysis_tools
WHERE tool_description LIKE '%velocity%';

SELECT AVG(magnitude) AS average_magnitude
FROM earthquake_ruptures
WHERE magnitude > 6 AND rupture_date > '1990-01-01';

SELECT report_name 
FROM reports 
WHERE report_id BETWEEN 1 AND 20;

SELECT magnitude
FROM earthquake_ruptures
WHERE rupture_id = 1;

SELECT fault_name, fault_type
FROM faults
WHERE fault_type = 'reverse' AND fault_id > 5 AND fault_name LIKE 'H%t';

SELECT fault_id, fault_name, fault_type
FROM faults
WHERE fault_type = 'normal';
